using UnityEngine;
public class GlazePanelController : MonoBehaviour
{
    public void Refresh()
    {
        if (glazeSystem == null)
        {
            return;
        }

        glazeSystem.LoadTargetFromCurrentOrder();

        float kaolin = GetSliderValue(kaolinSlider);
        float ash = GetSliderValue(ashSlider);
        float copper = GetSliderValue(copperSlider);
        float iron = GetSliderValue(ironSlider);
        float cobalt = GetSliderValue(cobaltSlider);

        SetText(kaolinValueText, kaolin.ToString("0.00"));
        SetText(ashValueText, ash.ToString("0.00"));
        SetText(copperValueText, copper.ToString("0.00"));
        SetText(ironValueText, iron.ToString("0.00"));
        SetText(cobaltValueText, cobalt.ToString("0.00"));

        float match = glazeSystem.CalculateGlazeMatch(kaolin, ash, copper, iron, cobalt);
        SetText(glazeMatchText, "Glaze Match: " + match.ToString("0") + "%");
    }
    private void RegisterListeners()
    {
        AddListener(kaolinSlider);
        AddListener(ashSlider);
        AddListener(copperSlider);
        AddListener(ironSlider);
        AddListener(cobaltSlider);
    }
    private void UnregisterListeners()
    {
        RemoveListener(kaolinSlider);
        RemoveListener(ashSlider);
        RemoveListener(copperSlider);
        RemoveListener(ironSlider);
        RemoveListener(cobaltSlider);
    }
    private void AddListener(Slider slider)
    {
        if (slider != null)
        {
